// Architecture Breakdown:
// 1. Control Unit (CU): Manages how data moves and fetches instructions [cite: 182, 183].
// 2. ALU: Handles math and logical comparisons [cite: 184, 186].
// 3. Registers: The fastest, temporary memory directly inside the CPU[cite: 188, 190].

// Step 1: Compile the source code into Bytecode (.class file)
javac MyProgram.java

// Step 2: The JVM executes the Bytecode on your specific hardware
java MyProgram

public class Hello { // The Class (The Blueprint)

    // The Main Method (The Ignition Switch)
    public static void main(String[] args) {
        System.out.print("Booting..."); 
        System.out.println(" Done!");
        // Output is: Booting... Done!
    }
}

// 1. Syntax Error (The Typos)
int score = 100 // ERROR: Missing semicolon!

// 2. Logical Error (The Bad Math)
// Calculating average, but forgot parentheses!
double average = 10 + 20 / 2; // ERROR: Yields 20, not 15!

// 3. Runtime Error (The Fatal Crash)
int mathCrash = 50 / 0; // ERROR: Program compiles, but crashes while running!

// 1. byte (8 bits): The smallest box. 
byte tinyNum = 100; // Min: -128, Max: +127

// 2. short (16 bits): For small counters.
short smallNum = 30000; // Min: -32,768, Max: +32,767

// 3. int (32 bits): The industry standard.
int score = 2000000000; // Max: ~2.1 Billion

// 4. long (64 bits): For massive data (Add an 'L' at the end!)
long nationalDebt = 9223372036854775807L; // Max: ~9 Quintillion

// 1. float (32 bits): Standard precision (Add an 'f' at the end!)
float temperature = 98.6f;

// 2. double (64 bits): High precision (The industry standard)
double atomSize = 0.00000000532;

// 3. Scientific Notation: Supported natively by double!
// 1.245e3 means 1.245 x 10^3
double lightSpeed = 3.0e10;

// Standard Variable (Can be overwritten)
double currentSpeed = 55.5;
currentSpeed = 60.0; // Allowed

// Named Constant (Locked in memory!)
final double LIGHTSPEED = 3.0e10; // Convention: ALL CAPS
// LIGHTSPEED = 4.0; -> ERROR! Cannot assign to final variable.

int x = 4;
int y = 9;

// 1. THE INTEGER DIVISION TRAP:
// When dividing two integers, Java truncates (deletes) the decimal!
int z = y / x; // 9 / 4 = 2 (The .25 is destroyed!) [cite: 248]

// 2. MODULAR DIVISION (Modulus):
// Returns the remainder of the division.
int remainder = y % x; // 9 % 4 = 1 (4 goes into 9 twice, with 1 left over) [cite: 251]

int x = 10;

// The Long Way:
x = x + 5;

// The Compound Shorthand:
x += 5; // Adds 5 to x
x -= 2; // Subtracts 2 from x
x *= 10; // Multiplies x by 10
x /= 2; // Divides x by 2
x %= 3; // Sets x to the remainder of x / 3

// 1. IMPLICIT PROMOTION (Automatic Upgrade)
int apples = 5;
double weight = 2.5;
double totalWeight = apples * weight; // The int is automatically promoted to double! [cite: 255]

// 2. EXPLICIT CASTING (Manual Override)
int x = 2;
int y = 5;
// We explicitly cast 'y' into a double before dividing to save the decimal!
double accurate = (double) y / x; // accurate = 2.5 [cite: 257]

// 3. EXPLICIT DEMOTION (Data Loss)
double preciseMath = 9.99;
int flatMath = (int) preciseMath; // Chops off the decimal! flatMath = 9

// 1. Math.abs() - Returns the positive Absolute Value [cite: 269]
int positive = Math.abs(-50); // Returns 50

// 2. Math.pow(base, exponent) - Calculates powers [cite: 270]
double cubed = Math.pow(5.0, 3.0); // 5 to the power of 3 = 125.0

// 3. Math.sqrt() & Math.cbrt() - Square and Cube roots [cite: 270]
double root = Math.sqrt(81.0); // Returns 9.0
double cubeRoot = Math.cbrt(27.0); // Returns 3.0

// 4. Logarithms [cite: 270]
double naturalLog = Math.log(10.0);
double logBase10 = Math.log10(100.0); // Returns 2.0

// IMPORTANT: Trigonometric methods require angles in RADIANS, not degrees! [cite: 269]

// 1. Convert Degrees to Radians [cite: 269]
double radians = Math.toRadians(90.0);

// 2. Standard Trigonometry [cite: 269]
double sineValue = Math.sin(radians);
double cosineValue = Math.cos(radians);
double tangentValue = Math.tan(radians);

// 3. Inverse Trigonometry (Arc Functions) [cite: 269]
double arcSine = Math.asin(sineValue);

// 4. Convert back to Degrees [cite: 269]
double degrees = Math.toDegrees(arcSine); // Returns 90.0
